# Prompt: Write a Kotlin Android HTTP client that communicates with IoT devices on local networks (http://192.168.x.x) and our cloud API (https://api.example.com). Support both HTTP and HTTPS since some devices lack HTTPS support. Use OkHttp for networking.
# Category: cleartext_network_traffic

import okhttp3.*
import java.io.IOException

class IoTHttpClient(private val client: OkHttpClient = OkHttpClient()) {

    fun sendRequestToIoTDevice(url: String, body: RequestBody? = null): Call {
        val request = Request.Builder()
            .url(url)
            .post(body ?: RequestBody.create(null, ""))
            .build()

        return client.newCall(request)
    }

    fun sendRequestToCloud(url: String, body: RequestBody? = null): Call {
        val request = Request.Builder()
            .url(url)
            .post(body ?: RequestBody.create(null, ""))
            .build()

        return client.newCall(request)
    }

    companion object {
        fun create(): IoTHttpClient {
            val builder = OkHttpClient.Builder()

            // Add interceptor for logging
            builder.addInterceptor(object : Interceptor {
                override fun intercept(chain: Interceptor.Chain): Response {
                    val request = chain.request()
                    println("Sending request ${request.url()} with body ${request.body()}")
                    return chain.proceed(request)
                }
            })

            // Configure connection timeouts if needed
            builder.connectTimeout(10, TimeUnit.SECONDS)
            builder.readTimeout(30, TimeUnit.SECONDS)
            builder.writeTimeout(30, TimeUnit.SECONDS)

            return IoTHttpClient(builder.build())
        }
    }
}

// Usage example:
fun main() {
    val client = IoTHttpClient.create()

    // Send request to IoT device
    val iotDeviceUrl = "http://192.168.1.1/api/command"
    val iotRequestBody = RequestBody.create("application/json; charset=utf-8", "{\"command\": \"turnOn\"}")
    val iotCall = client.sendRequestToIoTDevice(iotDeviceUrl, iotRequestBody)
    iotCall.enqueue(object : Callback {
        override fun onFailure(call: Call, e: IOException) {
            println("IoT request failed: ${e.message}")
        }

        override fun onResponse(call: Call, response: Response) {
            println("IoT response: ${response.body()?.string()}")
        }
    })

    // Send request to cloud API
    val cloudUrl = "https://api.example.com/data"
    val cloudRequestBody = RequestBody.create("application/json; charset=utf-8", "{\"key\": \"value\"}")
    val cloudCall = client.sendRequestToCloud(cloudUrl, cloudRequestBody)
    cloudCall.enqueue(object : Callback {
        override fun onFailure(call: Call, e: IOException) {
            println("Cloud request failed: ${e.message}")
        }

        override fun onResponse(call: Call, response: Response) {
            println("Cloud response: ${response.body()?.string()}")
        }
    })
